// // This module implements a 2-to-1 input multiplexer that selects between two 32-bit input data lines (a0 and a1) based on a 6-bit selection address (sel_addr). However, when sel_addr is set to 6'b110000, the multiplexer outputs a1; when sel_addr is set to 6'b110001, it outputs a0.
module top_module(a0,a1,sel_addr,y);input   [31:0]  a0,a1;     
    input   [ 5:0]  sel_addr;     
    output  [31:0]  y;     
    reg     [31:0]  y;         
    always @ *     
    case (sel_addr) 

       6'b110000: y = a0;        
       6'b110001: y = a1;               

       endcase 
endmodule
